# Create a client for the third-party insurance service
client = zeep.Client("http://www.insurance.com/webservices/policyLookup")

# Define the SOAP XML body
body = """
    <ns0:policyLookup xmlns:ns0="http://www.insurance.com/webservices">
        <ns0:policyNumber>{}</ns0:policyNumber>
        <ns0:customerName>{}</ns0:customerName>
    </ns0:policyLookup>
"""

# Get the user input for policy number and customer name
policy_number = input("Enter policy number: ")
